UPDATE game_player_mileage gpm JOIN (
SELECT #{item.id} AS id, #{item.tmpName} AS tmp_name, #{item.serverId} AS server_id, #{item.axisX} AS axis_x, #{item.axisY} AS axis_y, #{item.heading} AS heading, #{item.distance} AS distance, #{item.todayDistance} AS today_distance, #{item.updateTime} AS update_time
) gpmu ON gpmu.id = gpm.id SET gpm.tmp_name = gpmu.tmp_name, gpm.server_id = gpmu.server_id, gpm.axis_x = gpmu.axis_x, gpm.axis_y = gpmu.axis_y, gpm.heading = gpmu.heading, gpm.distance = gpmu.distance, gpm.today_distance = gpmu.today_distance, gpm.update_time = gpmu.update_time
